content.text:
{
  "核心的メッセージ": "人生の悩みは“考え方と欲望の再設計”で和らぐ。ソクラテス、エピクロス、セネカ、モンテーニュ、ショーペンハウアー、ニーチェの実践的洞察を使えば、不人気・貧しさ・苛立ち・劣等感・失恋・困難に現実的な慰めを与えられる。",
  "エグゼクティブ・サマリー（「要約=問い×答え×根拠（Why＝なぜそうなのか？&How=そのためには？）」の形式で、そこさえ見れば本を読まずとも理解できるようにまとめる）": {
    "問い": "現代人の具体的な苦悩（不人気、金銭、苛立ち、劣等感、失恋、困難）をどう和らげ、生きやすくできるか？",
    "答え": "6人の哲学者の核心概念を“生活の処方箋”として適用する。人気より徳（ソクラテス）、欲求の節約（エピクロス）、可否二分法（セネカ）、等身大の自己受容（モンテーニュ）、恋の生物学的理解（ショーペンハウアー）、運命愛（ニーチェ）。",
    "Why": "彼らの思想は人間の評価不安・過剰欲求・誤った期待・比較癖・執着・逆境回避のメカニズムを直視し、“判断の基準と欲望の構造”を変えることで苦痛の意味づけを転換できるから。",
    "How": "各章で(1)悩みを具体化→(2)哲学者の生涯と概念を抽出→(3)現代の場面に当てはめ→(4)実践ガイドに落とす。例: 多数意見より理性、欲求を分類し削減、制御可能/不可能を峻別、欠点を観察し受容、恋を種の戦略と理解、逆境を成長素材に肯定。"
  },
  "主要概念の説明（各概念を1〜2文で定義。可能なら一言要約も）": [
    {
      "概念": "慰めとしての哲学",
      "定義": "哲学を抽象理論ではなく生活改善の処方箋として用いる態度。読者の具体的な苦境に効く原理を抽出する。",
      "一言要約": "実用哲学"
    },
    {
      "概念": "世評と徳（ソクラテス）",
      "定義": "多数意見や人気よりも吟味された理性と徳に従う。誤解や不人気は真理追求の副作用であると受け止める。",
      "一言要約": "人気より正しさ"
    },
    {
      "概念": "欲求の分類（エピクロス）",
      "定義": "欲求を“自然かつ必要/自然だが不要/虚栄的”に分け、満たすべきものを絞ることで心的コストを下げる。",
      "一言要約": "欲望ダイエット"
    },
    {
      "概念": "アタラクシア（エピクロス）",
      "定義": "苦痛の不在と心の平静を最高善とみなす状態。簡素さ・友情・思索で到達を目指す。",
      "一言要約": "心の静けさ"
    },
    {
      "概念": "可否二分法（セネカ/ストア派）",
      "定義": "自分で制御できるものとできないものを峻別し、前者に専念し後者は受容する判断枠組み。",
      "一言要約": "コントロール焦点"
    },
    {
      "概念": "期待管理（セネカ）",
      "定義": "障害や遅延をあらかじめ想定し、怒りの燃料である過大期待を抜く技法。",
      "一言要約": "予見で鎮静"
    },
    {
      "概念": "自己受容の技法（モンテーニュ）",
      "定義": "人間の不完全さを観察し、借り物の理想から距離を取り“等身大”を肯定する態度。",
      "一言要約": "等身大で生きる"
    },
    {
      "概念": "意志と恋愛（ショーペンハウアー）",
      "定義": "恋は種の存続を図る盲目的意志の策略で、個人の幸福と齟齬を起こしやすい。",
      "一言要約": "恋は生物学"
    },
    {
      "概念": "アモール・ファティ（ニーチェ）",
      "定義": "運命を愛し、苦難を成長と意味の源として積極的に肯定する。",
      "一言要約": "運命愛"
    },
    {
      "概念": "試練の価値化（ニーチェ）",
      "定義": "逆境を避ける対象ではなく能力増大の素材として再評価する認知転換。",
      "一言要約": "逆境資源化"
    }
    ],
  "概念間の関係性や因果関係（箇条書きや簡易図式テキストで可）": [
    "社会的評価依存 → 不人気の苦痛 → ソクラテスの徳中心 → 自尊の再構築",
    "所得不足感 → 過剰欲求 → エピクロスの欲求分類 → 支出より欲望を削減 → 満足の増大",
    "期待と現実の齟齬 → 苛立ち/怒り → ストア派の可否二分法 → 統制感と平静の回復",
    "比較と理想化 → 劣等感 → モンテーニュの自己観察・受容 → 等身大の安定",
    "恋の理想化/執着 → 失恋の絶望 → 生殖戦略という視点 → 個人的悲劇の相対化",
    "逆境回避 → 停滞/脆弱性 → ニーチェの運命愛 → 試練を意味づけ → 成長",
    "期待管理は“不人気・金銭・失恋”各章に横断的に作用して痛点を鈍化させる",
    "自己受容は“世評への耐性”を高め、徳中心と相互補強する",
    "アタラクシアは“欲求削減”と“可否二分法”の実践結果として生起する"
  ],
  "構造と論理展開（章構成の要点や議論の流れを説明）": {
    "章構成": [
      { "章": 1, "悩み": "不人気", "哲学者": "ソクラテス", "処方": "多数意見ではなく理性と徳を基準にする" },
      { "章": 2, "悩み": "お金が足りない感", "哲学者": "エピクロス", "処方": "欲求の分類と簡素な快の重視で“足る”を増やす" },
      { "章": 3, "悩み": "挫折・苛立ち", "哲学者": "セネカ", "処方": "可否二分法と期待管理で怒りを無力化" },
      { "章": 4, "悩み": "不全感・劣等感", "哲学者": "モンテーニュ", "処方": "等身大の自己受容と観察で比較地獄を離脱" },
      { "章": 5, "悩み": "失恋", "哲学者": "ショーペンハウアー", "処方": "恋を生殖戦略として相対化し執着を緩める" },
      { "章": 6, "悩み": "困難・逆境", "哲学者": "ニーチェ", "処方": "運命愛で試練を意味づけし成長へ転化" }
    ],
    "論理の流れ": "問題提示 → 哲学者の生涯と思想の要点 → 概念の抽出 → 現代の具体例に適用 → 実践的指針・慰め → 章末の含意の要約",
